import React from "react";
import { Link } from "react-router-dom";

import img from "../images/download.jpg"
import logo from "../images/logo1.png"
export default function Home() {
  return (





      <div
        className="d-flex align-items-center justify-content-center text-center flex-dirextion text-dark"
        style={{
          minHeight: "90vh",
          backgroundImage:
            `url(${img})`,
          backgroundSize: "cover",
          backgroundPosition: "center",
        }}
      >
             <img src={logo} alt="" width="200px" />
        <div className="bg-transparent p-5 rounded shadow-lg">
          <h1 className="display-4 fw-bold text-white">Best food for your taste</h1>
          <p className="lead my-3 text-white">
            Discover delectable cuisine and unforgettable moments in our
            welcoming, culinary haven.
          </p>
          <div>
         
            <Link to="/menu" className="btn bg-success  text-white btn-outline-dark btn-lg">
              Explore Menu
            </Link>
          </div>
        </div>
     
    </div>
  );
}
